checker_dsl:
EXISTS (`taint flow path P`) {
  AND {
    EXISTS (`source node S`) {
      AND {
        (`S is an ActiveThreatModelSource`),
        NOT { (`S is a SafeHeaderSplittingSource`) }
      }
    },
    EXISTS (`sink node K`) {
      (`K is a HeaderSplittingSink`)
    },
    EXISTS (`barrier node B`) {
      OR {
        (`B is a SimpleTypeSanitizer`),
        EXISTS (`method call MC`, `compile-time constant expression CT`) {
          AND {
            (`B's expression equals MC`),
            (`MC calls a method from java.lang.String class`),
            (`CT is the first argument of MC`),
            OR {
              AND {
                (`MC's method name is "replace"`),
                OR {
                  (`CT's integer value equals 10`),
                  (`CT's integer value equals 13`)
                }
              },
              AND {
                (`MC's method name is "replaceAll"`),
                (`CT's string value matches regex pattern .*([\n\r]|\[\[\^[^\]\r\n]*\]).*`)
              }
            }
          }
        }
      }
    },
    (`P flows from S to K respecting barriers B`)
  }
}
